async function post_anti_bullying_effectiveness(req: NextRequest): Promise<Response> {

  let body: Record<string, unknown>;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON body" }, { status: 400 });
  }

  const {
    incidents,
    surveys,
    policy,
    training,
    homeId,
    periodStart,
    periodEnd,
  } = body as {
    incidents?: BullyingIncident[];
    surveys?: ChildBullyingSurvey[];
    policy?: AntiBullyingPolicy | null;
    training?: StaffAntiBullyingTraining[];
    homeId?: string;
    periodStart?: string;
    periodEnd?: string;
  };

  if (!periodStart || !periodEnd) {
    return NextResponse.json(
      { error: "periodStart and periodEnd are required" },
      { status: 400 },
    );
  }

  const result = generateAntiBullyingEffectivenessIntelligence(
    incidents ?? [],
    surveys ?? [],
    policy ?? null,
    training ?? [],
    homeId ?? "unknown",
    periodStart,
    periodEnd,
  );

  return NextResponse.json({ data: result });
}

