async function post_body_map_protocol(req: NextRequest): Promise<Response> {

  let body: Record<string, unknown>;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON body" }, { status: 400 });
  }

  const { records, audits, training, escalations, homeId, periodStart, periodEnd } = body as {
    records?: BodyMapRecord[];
    audits?: BodyMapAudit[];
    training?: BodyMapTraining[];
    escalations?: SafeguardingEscalation[];
    homeId?: string;
    periodStart?: string;
    periodEnd?: string;
  };

  if (!periodStart || !periodEnd) {
    return NextResponse.json({ error: "periodStart and periodEnd are required" }, { status: 400 });
  }

  const result = generateBodyMapProtocolIntelligence(
    records ?? [],
    audits ?? [],
    training ?? [],
    escalations ?? [],
    homeId ?? "unknown",
    periodStart,
    periodEnd,
  );

  return NextResponse.json({ data: result });
}

