async function get_children_fund_management(req: NextRequest): Promise<Response> {

  const { searchParams } = new URL(req.url);
  const mode = searchParams.get("mode") ?? "dashboard";
  const homeId = searchParams.get("homeId") ?? "home-oak";
  const childId = searchParams.get("childId");

  if (mode === "dashboard") {
    const intelligence = generateChildrenFundManagementIntelligence(
      children_fund_management_DEMO_ACCOUNTS,
      children_fund_management_DEMO_TRANSACTIONS,
      children_fund_management_DEMO_SESSIONS,
      children_fund_management_DEMO_AUDITS,
      homeId,
      children_fund_management_PERIOD_START,
      children_fund_management_PERIOD_END,
    );
    return NextResponse.json(intelligence);
  }

  if (mode === "child" && childId) {
    const account = children_fund_management_DEMO_ACCOUNTS.find((a) => a.childId === childId);
    if (!account) {
      return NextResponse.json({ error: "Child not found" }, { status: 404 });
    }
    const transactions = children_fund_management_DEMO_TRANSACTIONS.filter((t) => t.childId === childId);
    const sessions = children_fund_management_DEMO_SESSIONS.filter((s) => s.childId === childId);
    const profiles = buildChildFinancialProfiles([account], transactions, sessions);
    return NextResponse.json({ account, transactions, sessions, profile: profiles[0] });
  }

  if (mode === "accounts") {
    const result = evaluateAccountManagement(children_fund_management_DEMO_ACCOUNTS);
    return NextResponse.json({ accounts: children_fund_management_DEMO_ACCOUNTS, result });
  }

  if (mode === "transactions") {
    const result = evaluateTransactionIntegrity(children_fund_management_DEMO_TRANSACTIONS);
    return NextResponse.json({ transactions: children_fund_management_DEMO_TRANSACTIONS, result });
  }

  if (mode === "literacy") {
    const result = evaluateFinancialLiteracy(children_fund_management_DEMO_SESSIONS);
    return NextResponse.json({ sessions: children_fund_management_DEMO_SESSIONS, result });
  }

  if (mode === "audits") {
    const result = evaluateAuditCompliance(children_fund_management_DEMO_AUDITS);
    return NextResponse.json({ audits: children_fund_management_DEMO_AUDITS, result });
  }

  return NextResponse.json({ error: "Invalid mode" }, { status: 400 });
}

async function post_children_fund_management(req: NextRequest): Promise<Response> {

  const body = await req.json();
  const { action } = body;

  if (action === "evaluate") {
    const {
      accounts = [] as ChildAccount[],
      transactions = [] as FinancialTransaction[],
      sessions = [] as FinancialLiteracySession[],
      audits = [] as FinancialAudit[],
      homeId = "home-oak",
      periodStart = children_fund_management_PERIOD_START,
      periodEnd = children_fund_management_PERIOD_END,
    } = body;

    const intelligence = generateChildrenFundManagementIntelligence(
      accounts,
      transactions,
      sessions,
      audits,
      homeId,
      periodStart,
      periodEnd,
    );
    return NextResponse.json(intelligence);
  }

  if (action === "evaluate_accounts") {
    const accounts = body.accounts as ChildAccount[];
    if (!accounts) {
      return NextResponse.json({ error: "Missing accounts" }, { status: 400 });
    }
    return NextResponse.json(evaluateAccountManagement(accounts));
  }

  if (action === "evaluate_transactions") {
    const transactions = body.transactions as FinancialTransaction[];
    if (!transactions) {
      return NextResponse.json({ error: "Missing transactions" }, { status: 400 });
    }
    return NextResponse.json(evaluateTransactionIntegrity(transactions));
  }

  if (action === "evaluate_literacy") {
    const sessions = body.sessions as FinancialLiteracySession[];
    if (!sessions) {
      return NextResponse.json({ error: "Missing sessions" }, { status: 400 });
    }
    return NextResponse.json(evaluateFinancialLiteracy(sessions));
  }

  if (action === "evaluate_audits") {
    const audits = body.audits as FinancialAudit[];
    if (!audits) {
      return NextResponse.json({ error: "Missing audits" }, { status: 400 });
    }
    return NextResponse.json(evaluateAuditCompliance(audits));
  }

  return NextResponse.json({ error: "Invalid action" }, { status: 400 });
}

