async function post_communication_accessibility(request: NextRequest): Promise<Response> {

  try {
    const body = await request.json();
    const {
      profiles,
      assessments,
      documents,
      training,
      childIds,
      childNames,
      staffIds,
      homeId,
      periodStart,
      periodEnd,
      referenceDate,
    } = body;

    if (
      !profiles ||
      !assessments ||
      !documents ||
      !training ||
      !childIds ||
      !childNames ||
      !staffIds ||
      !homeId ||
      !periodStart ||
      !periodEnd ||
      !referenceDate
    ) {
      return NextResponse.json(
        {
          error:
            "Missing required fields: profiles, assessments, documents, training, childIds, childNames, staffIds, homeId, periodStart, periodEnd, referenceDate",
        },
        { status: 400 },
      );
    }

    if (
      !Array.isArray(profiles) ||
      !Array.isArray(assessments) ||
      !Array.isArray(documents) ||
      !Array.isArray(training) ||
      !Array.isArray(childIds) ||
      !Array.isArray(staffIds)
    ) {
      return NextResponse.json(
        {
          error:
            "profiles, assessments, documents, training, childIds, and staffIds must be arrays",
        },
        { status: 400 },
      );
    }

    if (typeof childNames !== "object" || childNames === null) {
      return NextResponse.json(
        { error: "childNames must be an object" },
        { status: 400 },
      );
    }

    const result = generateCommunicationAccessibilityIntelligence(
      profiles,
      assessments,
      documents,
      training,
      childIds,
      childNames,
      staffIds,
      homeId,
      periodStart,
      periodEnd,
      referenceDate,
    );
    return NextResponse.json(result);
  } catch (error) {
    return NextResponse.json(
      {
        error: "Failed to process communication & accessibility data",
        details: String(error),
      },
      { status: 500 },
    );
  }
}

