async function get_disability_reasonable_adjustments(req: NextRequest): Promise<Response> {

  try {
    const { adjustments, audits, equipment, training } = disability_reasonable_adjustments_getDemoData();
    const referenceDate = new Date().toISOString().split("T")[0];

    const result = generateDisabilityReasonableAdjustmentsIntelligence(
      adjustments,
      audits,
      equipment,
      training,
      "oak-house",
      "2026-01-01",
      "2026-06-30",
      referenceDate,
    );

    return NextResponse.json({
      data: {
        ...result,
        meta: {
          disabilityTypeLabels,
          adjustmentStatusLabels,
          equipmentConditionLabels,
          reviewOutcomeLabels,
          ratingLabels,
        },
      },
    });
  } catch (error) {
    return NextResponse.json(
      {
        error:
          "Failed to generate disability & reasonable adjustments intelligence",
        details: String(error),
      },
      { status: 500 },
    );
  }
}

async function post_disability_reasonable_adjustments(request: NextRequest): Promise<Response> {

  try {
    const body = await request.json();
    const {
      adjustments,
      audits,
      equipment,
      training,
      homeId,
      periodStart,
      periodEnd,
      referenceDate,
    } = body;

    if (
      !adjustments ||
      !audits ||
      !equipment ||
      !training ||
      !homeId ||
      !periodStart ||
      !periodEnd ||
      !referenceDate
    ) {
      return NextResponse.json(
        {
          error:
            "Missing required fields: adjustments, audits, equipment, training, homeId, periodStart, periodEnd, referenceDate",
        },
        { status: 400 },
      );
    }

    if (
      !Array.isArray(adjustments) ||
      !Array.isArray(audits) ||
      !Array.isArray(equipment) ||
      !Array.isArray(training)
    ) {
      return NextResponse.json(
        {
          error:
            "adjustments, audits, equipment, and training must be arrays",
        },
        { status: 400 },
      );
    }

    const result = generateDisabilityReasonableAdjustmentsIntelligence(
      adjustments as AdjustmentRecord[],
      audits as AccessibilityAudit[],
      equipment as EquipmentRecord[],
      training as StaffDisabilityTraining[],
      homeId,
      periodStart,
      periodEnd,
      referenceDate,
    );

    return NextResponse.json({
      data: {
        ...result,
        meta: {
          disabilityTypeLabels,
          adjustmentStatusLabels,
          equipmentConditionLabels,
          reviewOutcomeLabels,
          ratingLabels,
        },
      },
    });
  } catch (error) {
    return NextResponse.json(
      {
        error: "Failed to process disability & reasonable adjustments data",
        details: String(error),
      },
      { status: 500 },
    );
  }
}

