async function get_lessons_learned(req: NextRequest): Promise<Response> {

  const { incidents, reviews } = lessons_learned_generateDemoData();
  const result = generateLearningOrganisationScore(
    incidents,
    reviews,
    "oak-house",
    "2026-05-01",
    "2026-05-18",
    "2026-05-18",
  );

  return NextResponse.json({
    data: {
      ...result,
      meta: {
        incidentSummary: incidents.map((i) => ({
          id: i.id,
          date: i.date,
          category: getCategoryLabel(i.category),
          severity: i.severity,
          childName: i.childName,
        })),
        reviewCount: reviews.length,
        ratingLabel: getRatingLabel(result.rating),
      },
    },
  });
}

async function post_lessons_learned(req: NextRequest): Promise<Response> {

  let body: Record<string, unknown>;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON body" }, { status: 400 });
  }

  const { incidents, reviews, homeId, periodStart, periodEnd, currentDate } = body as {
    incidents?: IncidentRecord[];
    reviews?: PostIncidentReview[];
    homeId?: string;
    periodStart?: string;
    periodEnd?: string;
    currentDate?: string;
  };

  if (!incidents || !Array.isArray(incidents)) {
    return NextResponse.json(
      { error: "incidents array is required" },
      { status: 400 },
    );
  }
  if (!reviews || !Array.isArray(reviews)) {
    return NextResponse.json(
      { error: "reviews array is required" },
      { status: 400 },
    );
  }
  if (!periodStart || !periodEnd) {
    return NextResponse.json(
      { error: "periodStart and periodEnd are required (YYYY-MM-DD)" },
      { status: 400 },
    );
  }

  const result = generateLearningOrganisationScore(
    incidents,
    reviews,
    homeId ?? "unknown",
    periodStart,
    periodEnd,
    currentDate ?? new Date().toISOString().split("T")[0],
  );

  return NextResponse.json({ data: result });
}

