async function post_medication_management(req: NextRequest): Promise<Response> {

  let body: Record<string, unknown>;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON body" }, { status: 400 });
  }

  const {
    records,
    errors,
    stockChecks,
    selfAdminAssessments,
    cdRecords,
    homeId,
    periodStart,
    periodEnd,
    referenceDate,
  } = body as {
    records?: MedicationRecord[];
    errors?: MedicationError[];
    stockChecks?: StockCheck[];
    selfAdminAssessments?: SelfAdminAssessment[];
    cdRecords?: ControlledDrugRecord[];
    homeId?: string;
    periodStart?: string;
    periodEnd?: string;
    referenceDate?: string;
  };

  if (!records || !Array.isArray(records)) {
    return NextResponse.json({ error: "records array is required" }, { status: 400 });
  }
  if (!periodStart || !periodEnd) {
    return NextResponse.json({ error: "periodStart and periodEnd are required" }, { status: 400 });
  }

  const result = generateMedicationManagementIntelligence(
    records,
    errors ?? [],
    stockChecks ?? [],
    selfAdminAssessments ?? [],
    cdRecords ?? [],
    homeId ?? "unknown",
    periodStart,
    periodEnd,
    referenceDate ?? new Date().toISOString().split("T")[0],
  );

  return NextResponse.json({ data: result });
}

