async function get_multi_agency(req: NextRequest): Promise<Response> {

  const { searchParams } = new URL(req.url);
  const mode = searchParams.get("mode") ?? "dashboard";
  const homeId = searchParams.get("homeId") ?? "home-oak";
  const childId = searchParams.get("childId");

  if (mode === "dashboard") {
    const homeProfiles = multi_agency_DEMO_PROFILES.filter(p => p.homeId === homeId);
    const metrics = calculateHomeMultiAgencyMetrics(homeProfiles, homeId, multi_agency_NOW);
    const childResults = homeProfiles.map(p => evaluateMultiAgencyCompliance(p, multi_agency_NOW));
    return NextResponse.json({ metrics, childResults, profiles: homeProfiles });
  }

  if (mode === "child" && childId) {
    const profile = multi_agency_DEMO_PROFILES.find(p => p.childId === childId);
    if (!profile) {
      return NextResponse.json({ error: "Child not found" }, { status: 404 });
    }
    const result = evaluateMultiAgencyCompliance(profile, multi_agency_NOW);
    return NextResponse.json({ result, profile });
  }

  if (mode === "metrics") {
    const homeProfiles = multi_agency_DEMO_PROFILES.filter(p => p.homeId === homeId);
    const metrics = calculateHomeMultiAgencyMetrics(homeProfiles, homeId, multi_agency_NOW);
    return NextResponse.json(metrics);
  }

  return NextResponse.json({ error: "Invalid mode" }, { status: 400 });
}

async function post_multi_agency(req: NextRequest): Promise<Response> {

  const body = await req.json();
  const { action } = body;

  if (action === "evaluate") {
    const profile = body.profile as ChildMultiAgencyProfile;
    if (!profile) {
      return NextResponse.json({ error: "Missing profile" }, { status: 400 });
    }
    const result = evaluateMultiAgencyCompliance(profile, body.now ?? multi_agency_NOW);
    return NextResponse.json(result);
  }

  if (action === "metrics") {
    const profiles = body.profiles as ChildMultiAgencyProfile[];
    const homeId = body.homeId as string;
    if (!profiles || !homeId) {
      return NextResponse.json({ error: "Missing profiles or homeId" }, { status: 400 });
    }
    const metrics = calculateHomeMultiAgencyMetrics(profiles, homeId, body.now ?? multi_agency_NOW);
    return NextResponse.json(metrics);
  }

  return NextResponse.json({ error: "Invalid action" }, { status: 400 });
}

