async function get_nutrition_hydration_monitoring(req: NextRequest): Promise<Response> {

  const { meals, hydrationRecords, policy, training } = nutrition_hydration_monitoring_generateDemoData();

  const result = generateNutritionHydrationMonitoringIntelligence(
    meals,
    hydrationRecords,
    policy,
    training,
    "oak-house",
    "2026-01-01",
    "2026-05-19",
  );

  return NextResponse.json({
    data: {
      ...result,
      meta: {
        mealSummary: meals.map((m) => ({
          id: m.id,
          date: m.mealDate,
          child: m.childName,
          type: getMealTypeLabel(m.mealType),
          quality: getNutritionQualityLabel(m.nutritionQuality),
          portion: getPortionConsumedLabel(m.portionConsumed),
        })),
        ratingLabel: getRatingLabel(result.rating),
      },
    },
  });
}

async function post_nutrition_hydration_monitoring(req: NextRequest): Promise<Response> {

  let body: Record<string, unknown>;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON body" }, { status: 400 });
  }

  const {
    meals,
    hydrationRecords,
    policy,
    training,
    homeId,
    periodStart,
    periodEnd,
  } = body as {
    meals?: MealRecord[];
    hydrationRecords?: HydrationRecord[];
    policy?: NutritionPolicy | null;
    training?: StaffNutritionTraining[];
    homeId?: string;
    periodStart?: string;
    periodEnd?: string;
  };

  if (!periodStart || !periodEnd) {
    return NextResponse.json(
      { error: "periodStart and periodEnd are required" },
      { status: 400 },
    );
  }

  const result = generateNutritionHydrationMonitoringIntelligence(
    meals ?? [],
    hydrationRecords ?? [],
    policy ?? null,
    training ?? [],
    homeId ?? "unknown",
    periodStart,
    periodEnd,
  );

  return NextResponse.json({ data: result });
}

