async function post_parental_engagement(req: NextRequest): Promise<Response> {

  let body: Record<string, unknown>;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON body" }, { status: 400 });
  }

  const {
    contacts,
    support,
    plans,
    feedback,
    childIds,
    homeId,
    periodStart,
    periodEnd,
    referenceDate,
  } = body as {
    contacts?: ContactRecord[];
    support?: ParentalSupportRecord[];
    plans?: FamilyPlanRecord[];
    feedback?: ParentalFeedbackRecord[];
    childIds?: string[];
    homeId?: string;
    periodStart?: string;
    periodEnd?: string;
    referenceDate?: string;
  };

  if (!contacts || !Array.isArray(contacts)) {
    return NextResponse.json({ error: "contacts array is required" }, { status: 400 });
  }
  if (!periodStart || !periodEnd) {
    return NextResponse.json({ error: "periodStart and periodEnd are required" }, { status: 400 });
  }
  if (!childIds || !Array.isArray(childIds) || childIds.length === 0) {
    return NextResponse.json({ error: "childIds array is required" }, { status: 400 });
  }

  const result = generateParentalEngagementIntelligence(
    contacts,
    support ?? [],
    plans ?? [],
    feedback ?? [],
    childIds,
    homeId ?? "unknown",
    periodStart,
    periodEnd,
    referenceDate ?? new Date().toISOString().split("T")[0],
  );

  return NextResponse.json({ data: result });
}

