async function post_privacy_dignity_assessment(req: NextRequest): Promise<Response> {

  let body: Record<string, unknown>;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON body" }, { status: 400 });
  }

  const { audits, feedback, incidents, training, homeId, periodStart, periodEnd } = body as {
    audits?: PrivacyAudit[];
    feedback?: ChildPrivacyFeedback[];
    incidents?: PrivacyIncident[];
    training?: StaffPrivacyTraining[];
    homeId?: string;
    periodStart?: string;
    periodEnd?: string;
  };

  if (!periodStart || !periodEnd) {
    return NextResponse.json(
      { error: "periodStart and periodEnd are required" },
      { status: 400 },
    );
  }

  const result = generatePrivacyDignityIntelligence(
    audits ?? [],
    feedback ?? [],
    incidents ?? [],
    training ?? [],
    homeId ?? "unknown",
    periodStart,
    periodEnd,
  );

  return NextResponse.json({ data: result });
}

