async function post_professional_boundary_compliance(req: NextRequest): Promise<Response> {

  let body: Record<string, unknown>;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON body" }, { status: 400 });
  }

  const {
    audits,
    policy,
    training,
    homeId,
    periodStart,
    periodEnd,
  } = body as {
    audits?: BoundaryAudit[];
    policy?: BoundaryPolicy | null;
    training?: StaffBoundaryTraining[];
    homeId?: string;
    periodStart?: string;
    periodEnd?: string;
  };

  if (!periodStart || !periodEnd) {
    return NextResponse.json(
      { error: "periodStart and periodEnd are required" },
      { status: 400 },
    );
  }

  const result = generateProfessionalBoundaryComplianceIntelligence(
    audits ?? [],
    policy ?? null,
    training ?? [],
    homeId ?? "unknown",
    periodStart,
    periodEnd,
  );

  return NextResponse.json({ data: result });
}

