async function post_recreational_leisure_access(req: NextRequest): Promise<Response> {

  let body: Record<string, unknown>;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON body" }, { status: 400 });
  }

  const {
    activities,
    policy,
    training,
    homeId,
    periodStart,
    periodEnd,
  } = body as {
    activities?: LeisureActivity[];
    policy?: LeisurePolicy | null;
    training?: StaffLeisureTraining[];
    homeId?: string;
    periodStart?: string;
    periodEnd?: string;
  };

  if (!periodStart || !periodEnd) {
    return NextResponse.json(
      { error: "periodStart and periodEnd are required" },
      { status: 400 },
    );
  }

  const result = generateRecreationalLeisureAccessIntelligence(
    activities ?? [],
    policy ?? null,
    training ?? [],
    homeId ?? "unknown",
    periodStart,
    periodEnd,
  );

  return NextResponse.json({ data: result });
}

