async function get_regulatory_self_assessment(req: NextRequest): Promise<Response> {

  const homeId = "oak-house";

  const analysis = analyseSelfAssessment(
    regulatory_self_assessment_DEMO_ENTRIES,
    regulatory_self_assessment_DEMO_ACTIONS,
    regulatory_self_assessment_DEMO_FEEDBACK,
    homeId,
  );

  const criticalActions = getCriticalActions(regulatory_self_assessment_DEMO_ACTIONS, homeId);
  const overdueActions = getOverdueActions(regulatory_self_assessment_DEMO_ACTIONS, homeId);
  const unaddressedFeedback = getUnaddressedFeedback(regulatory_self_assessment_DEMO_FEEDBACK, homeId);

  return NextResponse.json({
    analysis,
    criticalActions,
    overdueActions,
    unaddressedFeedback,
  });
}

async function post_regulatory_self_assessment(req: NextRequest): Promise<Response> {

  const body = await req.json();
  const { entries, actions, feedback, homeId } = body;

  if (!entries || !homeId) {
    return NextResponse.json(
      { error: "Missing required fields: entries, homeId" },
      { status: 400 },
    );
  }

  if (!Array.isArray(entries)) {
    return NextResponse.json(
      { error: "entries must be an array" },
      { status: 400 },
    );
  }

  if (typeof homeId !== "string" || homeId.length === 0) {
    return NextResponse.json(
      { error: "homeId must be a non-empty string" },
      { status: 400 },
    );
  }

  if (actions && !Array.isArray(actions)) {
    return NextResponse.json(
      { error: "actions must be an array" },
      { status: 400 },
    );
  }

  if (feedback && !Array.isArray(feedback)) {
    return NextResponse.json(
      { error: "feedback must be an array" },
      { status: 400 },
    );
  }

  const analysis = analyseSelfAssessment(
    entries as SelfAssessmentEntry[],
    (actions ?? []) as ImprovementAction[],
    (feedback ?? []) as ExternalFeedback[],
    homeId,
  );

  const criticalActionsList = getCriticalActions(
    (actions ?? []) as ImprovementAction[],
    homeId,
  );
  const overdueActionsList = getOverdueActions(
    (actions ?? []) as ImprovementAction[],
    homeId,
  );
  const unaddressedFeedbackList = getUnaddressedFeedback(
    (feedback ?? []) as ExternalFeedback[],
    homeId,
  );

  return NextResponse.json({
    analysis,
    criticalActions: criticalActionsList,
    overdueActions: overdueActionsList,
    unaddressedFeedback: unaddressedFeedbackList,
  });
}

// ─── regulatory ────────────────────────────────────────────────────────
async function regulatory_handleLiveData(sb: any, homeId: string, view: string, year: number) {
  const [reportsRes, reviewsRes, notificationsRes] = await Promise.all([
    (sb.from("reg44_reports") as SB).select("*").eq("home_id", homeId),
    (sb.from("reg45_reviews") as SB).select("*").eq("home_id", homeId),
    (sb.from("statutory_notifications") as SB).select("*").eq("home_id", homeId),
  ]);

  if (reportsRes.error) throw reportsRes.error;
  if (reviewsRes.error) throw reviewsRes.error;
  if (notificationsRes.error) throw notificationsRes.error;

  const reports: Reg44Report[] = reportsRes.data ?? [];
  const reviews: Reg45Review[] = reviewsRes.data ?? [];
  const notifications: StatutoryNotification[] = notificationsRes.data ?? [];

  const now = new Date().toISOString();

  if (view === "compliance") {
    const compliance = evaluateRegulatoryCompliance(reports, reviews, notifications, homeId, now);
    return NextResponse.json({ compliance });
  }

  if (view === "actions") {
    const actionSummary = summarizeActionPoints(reports, now);
    return NextResponse.json({ actionSummary });
  }

  // Overview
  const compliance = evaluateRegulatoryCompliance(reports, reviews, notifications, homeId, now);
  const actionSummary = summarizeActionPoints(reports, now);

  return NextResponse.json({
    compliance,
    actionSummary,
    recentReports: reports.slice(0, 6),
    recentNotifications: notifications.slice(0, 10),
  });
}
