const room_standards_personalisation_roomConditionLabels = {
  excellent: "Excellent",
  good: "Good",
  fair: "Fair",
  poor: "Poor",
  needs_repair: "Needs Repair",
};
const room_standards_personalisation_personalisationLevelLabels = {
  highly_personalised: "Highly Personalised",
  personalised: "Personalised",
  some_personalisation: "Some Personalisation",
  minimal: "Minimal",
  none: "None",
};
const room_standards_personalisation_inspectionOutcomeLabels = {
  passed: "Passed",
  minor_issues: "Minor Issues",
  major_issues: "Major Issues",
  failed: "Failed",
};
const room_standards_personalisation_furnitureConditionLabels = {
  new: "New",
  good: "Good",
  fair: "Fair",
  poor: "Poor",
  replacement_needed: "Replacement Needed",
};
const room_standards_personalisation_ratingLabels = {
  outstanding: "Outstanding",
  good: "Good",
  requires_improvement: "Requires Improvement",
  inadequate: "Inadequate",
};

async function get_room_standards_personalisation(req: NextRequest): Promise<Response> {

  const { rooms, inspections, policy, training } = room_standards_personalisation_generateDemoData();

  const result = generateRoomStandardsPersonalisationIntelligence(
    rooms,
    inspections,
    policy,
    training,
    "oak-house",
    "2026-01-01",
    "2026-05-19",
  );

  return NextResponse.json({
    data: {
      ...result,
      meta: {
        room_standards_personalisation_roomConditionLabels,
        room_standards_personalisation_personalisationLevelLabels,
        room_standards_personalisation_inspectionOutcomeLabels,
        room_standards_personalisation_furnitureConditionLabels,
        room_standards_personalisation_ratingLabels,
        ratingLabel: getRatingLabel(result.rating),
        roomSummary: rooms.map((r) => ({
          id: r.id,
          childName: r.childName,
          condition: getRoomConditionLabel(r.roomCondition),
          personalisation: getPersonalisationLevelLabel(r.personalisationLevel),
          furniture: getFurnitureConditionLabel(r.furnitureCondition),
        })),
      },
    },
  });
}

async function post_room_standards_personalisation(req: NextRequest): Promise<Response> {

  let body: Record<string, unknown>;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON body" }, { status: 400 });
  }

  const {
    rooms,
    inspections,
    policy,
    training,
    homeId,
    periodStart,
    periodEnd,
  } = body as {
    rooms?: RoomRecord[];
    inspections?: RoomInspection[];
    policy?: RoomPolicy | null;
    training?: StaffRoomTraining[];
    homeId?: string;
    periodStart?: string;
    periodEnd?: string;
  };

  if (!periodStart || !periodEnd) {
    return NextResponse.json(
      { error: "periodStart and periodEnd are required" },
      { status: 400 },
    );
  }

  const result = generateRoomStandardsPersonalisationIntelligence(
    rooms ?? [],
    inspections ?? [],
    policy ?? null,
    training ?? [],
    homeId ?? "unknown",
    periodStart,
    periodEnd,
  );

  return NextResponse.json({ data: result });
}

