async function get_therapeutic(req: NextRequest): Promise<Response> {

  const { searchParams } = new URL(req.url);
  const mode = searchParams.get("mode") ?? "dashboard";

  if (mode === "dashboard") {
    const compliance = evaluateTherapeuticCompliance(therapeutic_DEMO_PROFILES, therapeutic_DEMO_CONFIG, therapeutic_NOW);
    const metrics = calculateHomeTherapeuticMetrics(therapeutic_DEMO_PROFILES, therapeutic_DEMO_CONFIG, therapeutic_NOW);
    return NextResponse.json({ compliance, metrics, profiles: therapeutic_DEMO_PROFILES, config: therapeutic_DEMO_CONFIG });
  }

  if (mode === "metrics") {
    const metrics = calculateHomeTherapeuticMetrics(therapeutic_DEMO_PROFILES, therapeutic_DEMO_CONFIG, therapeutic_NOW);
    return NextResponse.json(metrics);
  }

  if (mode === "child") {
    const childId = searchParams.get("childId");
    if (childId) {
      const profile = therapeutic_DEMO_PROFILES.find((p) => p.childId === childId);
      if (profile) return NextResponse.json(profile);
      return NextResponse.json({ error: "Child not found" }, { status: 404 });
    }
    return NextResponse.json(therapeutic_DEMO_PROFILES);
  }

  return NextResponse.json({ error: "Invalid mode" }, { status: 400 });
}

async function post_therapeutic(req: NextRequest): Promise<Response> {

  const body = await req.json();
  const { action } = body;

  if (action === "evaluate") {
    const profiles = body.profiles as ChildTherapeuticProfile[];
    const config = body.config as HomeTherapeuticConfig;
    if (!profiles || !config) {
      return NextResponse.json({ error: "Missing profiles or config" }, { status: 400 });
    }
    const result = evaluateTherapeuticCompliance(profiles, config, body.now ?? therapeutic_NOW);
    return NextResponse.json(result);
  }

  if (action === "metrics") {
    const profiles = body.profiles as ChildTherapeuticProfile[];
    const config = body.config as HomeTherapeuticConfig;
    if (!profiles || !config) {
      return NextResponse.json({ error: "Missing profiles or config" }, { status: 400 });
    }
    const result = calculateHomeTherapeuticMetrics(profiles, config, body.now ?? therapeutic_NOW);
    return NextResponse.json(result);
  }

  return NextResponse.json({ error: "Invalid action" }, { status: 400 });
}

