async function get_trauma_informed(req: NextRequest): Promise<Response> {

  try {
    const intelligence = generateTraumaInformedIntelligence(
      trauma_informed_DEMO_TRAINING,
      trauma_informed_DEMO_INTERVENTIONS,
      trauma_informed_DEMO_ADAPTATIONS,
      trauma_informed_DEMO_CONSULTATIONS,
      trauma_informed_DEMO_SCREENINGS,
      trauma_informed_CHILD_IDS,
      "home-oak",
      trauma_informed_PERIOD_START,
      trauma_informed_PERIOD_END,
      trauma_informed_REF_DATE
    );

    return NextResponse.json(intelligence);
  } catch (error) {
    return NextResponse.json(
      { error: "Failed to generate trauma-informed intelligence" },
      { status: 500 }
    );
  }
}

async function post_trauma_informed(request: NextRequest): Promise<Response> {

  try {
    const body = await request.json();

    const {
      training,
      interventions,
      adaptations,
      consultations,
      screenings,
      childIds,
      homeId,
      periodStart,
      periodEnd,
      referenceDate,
    } = body;

    // Validation
    if (!homeId || typeof homeId !== "string") {
      return NextResponse.json(
        { error: "homeId is required and must be a string" },
        { status: 400 }
      );
    }
    if (!periodStart || typeof periodStart !== "string") {
      return NextResponse.json(
        { error: "periodStart is required and must be a date string" },
        { status: 400 }
      );
    }
    if (!periodEnd || typeof periodEnd !== "string") {
      return NextResponse.json(
        { error: "periodEnd is required and must be a date string" },
        { status: 400 }
      );
    }
    if (!referenceDate || typeof referenceDate !== "string") {
      return NextResponse.json(
        { error: "referenceDate is required and must be a date string" },
        { status: 400 }
      );
    }
    if (!Array.isArray(childIds)) {
      return NextResponse.json(
        { error: "childIds must be an array of strings" },
        { status: 400 }
      );
    }
    if (!Array.isArray(training)) {
      return NextResponse.json(
        { error: "training must be an array" },
        { status: 400 }
      );
    }
    if (!Array.isArray(interventions)) {
      return NextResponse.json(
        { error: "interventions must be an array" },
        { status: 400 }
      );
    }
    if (!Array.isArray(adaptations)) {
      return NextResponse.json(
        { error: "adaptations must be an array" },
        { status: 400 }
      );
    }
    if (!Array.isArray(consultations)) {
      return NextResponse.json(
        { error: "consultations must be an array" },
        { status: 400 }
      );
    }
    if (!Array.isArray(screenings)) {
      return NextResponse.json(
        { error: "screenings must be an array" },
        { status: 400 }
      );
    }

    const intelligence = generateTraumaInformedIntelligence(
      training,
      interventions,
      adaptations,
      consultations,
      screenings,
      childIds,
      homeId,
      periodStart,
      periodEnd,
      referenceDate
    );

    return NextResponse.json(intelligence);
  } catch (error) {
    return NextResponse.json(
      { error: "Invalid request body" },
      { status: 400 }
    );
  }
}

